// ---------------------------------------------------------------
// Parse the generated dataset (lazy, once per Worker instance).
// Format per line: name|asciiName|countryCode|admin1|lat|lng|population
// ---------------------------------------------------------------
let datasetIndex = null;

function buildDatasetIndex() {
  const index = new Map(); // "name|CC" -> array of entries
  if (!CITIES_DATA || CITIES_DATA.length === 0) return index;
  for (const line of CITIES_DATA.split("\n")) {
    if (!line) continue;
    const parts = line.split("|");
    if (parts.length < 7) continue;
    const [name, ascii, cc, admin1, latS, lngS, popS] = parts;
    const entry = {
      name,
      country: cc,
      admin1,
      lat: parseFloat(latS),
      lng: parseFloat(lngS),
      pop: parseInt(popS, 10) || 0,
    };
    for (const key of new Set([
      `${name.toLowerCase()}|${cc}`,
      `${ascii.toLowerCase()}|${cc}`,
    ])) {
      if (!index.has(key)) index.set(key, []);
      index.get(key).push(entry);
    }
  }
  return index;
}

function normState(state) {
  return (state || "").trim().toLowerCase();
}

/**
 * Find coordinates for a city.
 * @param {string} cityName
 * @param {string} countryCode ISO-2 (e.g. "US")
 * @param {string} [state] optional state/province, used to break ties
 * @returns {{name, country, lat, lng, source} | null}
 */
export function findCity(cityName, countryCode, state) {
  const q = (cityName || "").trim().toLowerCase();
  const cc = (countryCode || "US").toUpperCase();
  const st = normState(state);
  if (!q) return fallbackNewYork();

  // Layer 1: full dataset
  if (datasetIndex === null) datasetIndex = buildDatasetIndex();
  const hits = datasetIndex.get(`${q}|${cc}`);
  if (hits && hits.length > 0) {
    let pick = hits;
    if (st) {
      const stateHits = hits.filter(
        (h) => h.admin1 && (h.admin1.toLowerCase() === st || h.admin1.toLowerCase().startsWith(st))
      );
      if (stateHits.length > 0) pick = stateHits;
    }
    const best = pick.reduce((a, b) => (b.pop > a.pop ? b : a));
    return { name: best.name, country: best.country, lat: best.lat, lng: best.lng, source: "dataset" };
  }

  // Layer 2: built-in major cities
  let candidates = MAJOR_CITIES.filter(([n, c]) => n === q && c === cc);
  if (candidates.length === 0) {
    candidates = MAJOR_CITIES.filter(([n]) => n === q); // any country
  }
  if (candidates.length > 0) {
    let pick = candidates[0];
    if (st) {
      const stMatch = candidates.find(([, , a1]) => a1 && a1.toLowerCase() === st);
      if (stMatch) pick = stMatch;
    }
    return { name: pick[0], country: pick[1], lat: pick[3], lng: pick[4], source: "fallback" };
  }

  // Layer 3: same last-resort behavior as the old code
  return fallbackNewYork();
}

function fallbackNewYork() {
  return { name: "new york", country: "US", lat: 40.71, lng: -74.01, source: "fallback-default" };
}
